import React, { useState, useEffect } from 'react';
import './Messages.css';
import { Avatar } from '@mui/material';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';
import EditIcon from '@mui/icons-material/Edit';

const Messages = () => {
    const [conversations, setConversations] = useState([]);
    const [selectedConversation, setSelectedConversation] = useState(null);
    const [newMessage, setNewMessage] = useState('');

    useEffect(() => {
        // Fetch conversations
        // Replace with actual API call
        setConversations([
            { _id: '1', name: 'John Doe', avatar: 'https://via.placeholder.com/40', messages: [] },
            { _id: '2', name: 'Jane Smith', avatar: 'https://via.placeholder.com/40', messages: [] },
        ]);
    }, []);

    const selectConversation = (conversation) => {
        setSelectedConversation(conversation);
    };

    const sendMessage = () => {
        if (newMessage.trim() && selectedConversation) {
            // Replace with actual API call
            const newMsg = { text: newMessage, sender: 'You' };
            setSelectedConversation({
                ...selectedConversation,
                messages: [...selectedConversation.messages, newMsg]
            });
            setNewMessage('');
        }
    };

    return (
        <div className="messages-container">
            <div className="conversations-list">
                <h2>Your Chats</h2>
                {conversations.map(conversation => (
                    <div 
                        key={conversation._id} 
                        className={`conversation-item ${selectedConversation?._id === conversation._id ? 'active' : ''}`}
                        onClick={() => selectConversation(conversation)}
                    >
                        <Avatar src={conversation.avatar} alt={conversation.name} />
                        <p>{conversation.name}</p>
                    </div>
                ))}
            </div>
            <div className="chat-window">
                {selectedConversation ? (
                    <div>
                        <div className="chat-header">
                            <button className="back-button" onClick={() => setSelectedConversation(null)}>
                                <ArrowBackIcon />
                            </button>
                            <h2>{selectedConversation.name}</h2>
                            <EditIcon className="edit-icon" />
                        </div>
                        <div className="messages">
                            {selectedConversation.messages.length > 0 ? (
                                selectedConversation.messages.map((message, index) => (
                                    <div key={index} className={`message ${message.sender === 'You' ? 'sent' : 'received'}`}>
                                        <p>{message.text}</p>
                                    </div>
                                ))
                            ) : (
                                <p className="no-messages">No messages yet. Start the conversation!</p>
                            )}
                        </div>
                        <div className="message-input">
                            <input 
                                type="text" 
                                value={newMessage} 
                                onChange={(e) => setNewMessage(e.target.value)} 
                                placeholder="Type a message..." 
                            />
                            <button onClick={sendMessage}>Send</button>
                        </div>
                    </div>
                ) : (
                    <p className="select-conversation">Select a conversation to start chatting</p>
                )}
            </div>
        </div>
    );
};

export default Messages;
